import { Component, ElementRef, ViewChild, ViewContainerRef } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { NgbModal } from '@ng-bootstrap/ng-bootstrap';
import { CommonService } from '../../../../../services/common.service';
import { ModalMessageComponent } from '../../../../../shared/components/modal-message/modal-message.component';
import { ViewFileComponent } from '../../../cashier/collect/payment-modal/view-file/view-file.component';
import { UnsettledSessionService } from '../../../cashier/unsettled-session/services/unsettled-session.service';
import { AllocationService } from '../../allocation/allocation/allocation-services/allocation.service';
import { ReceiptsService } from '../services/receipts.service';
import { MarkaziaVoucherService } from '../../../cashier/markazia-vouchers/services/markazia-voucher.service';
import { Subscription, catchError, forkJoin, of } from 'rxjs';
import { NgxSpinnerService } from 'ngx-spinner';
import { CollectService } from '../../../cashier/collect/services/collect.service';
import { DecimalPipe } from '@angular/common';
import { GeneralService } from '../../../../../services/general.service';

@Component({
  selector: 'app-create-receipt',
  templateUrl: './create-receipt.component.html',
  styleUrls: ['./create-receipt.component.scss']
})
export class CreateReceiptComponent {
  uploadedFile;
  formGroup: FormGroup;
  enter: boolean;
  invalidFileType: string;
  currencyList = [];
  employeeList = [];
  costCenterList = [];
  mfCategoryList = [];
  currencyName = '';
  fileTypes = ['image/jpeg', 'image/jpg', 'image/png', 'application/pdf'];//'application/pdf'
  subscriptions = new Subscription();
  dateYMD = new Date();
  @ViewChild('inputFile') inputFile!: ElementRef;
  @ViewChild('container') container: ElementRef;
  taxesList = [];
  constructor(
    private _generalService: GeneralService,
    private _receiptsService: ReceiptsService,
    private _voucherService: MarkaziaVoucherService,
    private _spinner: NgxSpinnerService,
    private _commonService: CommonService, private fb: FormBuilder,
    private _modalService: NgbModal,
    private _allocationService: AllocationService,
    private _collectService: CollectService,
    private _decimalPipe: DecimalPipe,
    private _unsettleSession: UnsettledSessionService) {
  }
  ngOnInit() {
    this.initForm();
    this.getCurrencyList();
    this.getLookups();
    this.f.get('mainFundPaymentCategoryID').valueChanges.subscribe(value => {
      this.toggleControlDisability(value);
    })

  }
  handleSearch(event: any) {
    this._collectService.customersList(event.term).subscribe((response: any) => {
      this.employeeList = response.data;
    })
  }
  customSearch(term: string, item: any): boolean {
    return item?.customerName?.toLowerCase().includes(term.toLowerCase()) ||
      item?.mobile?.toLowerCase().includes(term.toLowerCase())
  }
  getLookups() {
    //const employee = this._collectService.customersList().pipe(catchError(error => of(error)));
    const costCenter = this._voucherService.getCostCenter(`?StatusId=2001&PageSize=1000`).pipe(catchError(error => of(error)));
    const mainFundCat = this._receiptsService.getMainFundPaymentCategories(`?status=2001&PageSize=1000`).pipe(catchError(error => of(error)));
    let params = `?lookupTypeId=23&status=2001&pageSize=1000`;
    const taxes = this._generalService.getLookupsWithParams(params)
    forkJoin([costCenter, mainFundCat, taxes]).subscribe(data => {
      this.costCenterList = data[0].data;
      this.mfCategoryList = data[1].data;
      this.taxesList = (data[2] as any).data.map(x => {
        return {
          ...x,
          text: x.name[0].lookupName
        }
      });
    })
  }
  ngOnDestroy() {
    this.subscriptions.unsubscribe();
  }
  initForm() {
    this.formGroup = this.fb.group({
      accountID: [null],
      mainFundPaymentCategoryID: [null, [Validators.required]],
      paymentAmount: [{ value: '', disabled: true }, [Validators.required]],
      paymentTaxPer: [null, [Validators.required]],
      paymentTaxAmount: [{ value: '', disabled: true }, [Validators.required]],
      paymentTotalAmount: [{ value: '', disabled: true }, [Validators.required]],
      paymentCurrencyID: [null, [Validators.required]],
      paymentCostCenterID: [null, [Validators.required]],
      paymentAttachment: [''],
      notes: [''],
      dateYMD: [{ value: new Date(), disabled: true }], // Readonly
      time: [{ value: this.formatTime(new Date()), disabled: true }], // Readonly
    })
  }
  handleCurrencyChange(event) {
    this.currencyName = event?.text || '';
  }
  handleTaxChange(event) {
    this.handleAmountChange();
  }
  handleMfCategoryChange(event) {
    let obj = {
      paymentTaxPer: event?.taxPercentId || null,
      paymentCostCenterID: event?.costCenter?.costCenterId,
      paymentAmount: '',
      paymentTaxAmount: '',
      paymentTotalAmount: '',
    }
    this.f.patchValue(obj);
    this.handleAmountChange();
  }

  handleAmountChange() {
    let amount = + this.f.get('paymentAmount').value;
    let taxId = + this.f.get('paymentTaxPer').value;
    let taxPercentage = +(this.taxesList.find(x => x.id == taxId)?.name[0]?.lookupName);
    let taxAmount = (taxPercentage / 100) * amount;
    this.f.get('paymentTaxAmount').setValue(this._decimalPipe.transform(taxAmount, '2.3'));
    this.f.get('paymentTotalAmount').setValue(this._decimalPipe.transform(amount + taxAmount, '2.3'));
  }
  handleTotalAmountChange() {
    let totalAmount = + this.f.get('paymentTotalAmount').value;
    let taxId = + this.f.get('paymentTaxPer').value;
    let taxPercentage = +(this.taxesList.find(x => x.id == taxId)?.name[0]?.lookupName);
    let taxAmount = (totalAmount * taxPercentage) / (100 + taxPercentage);
    this.f.get('paymentTaxAmount').setValue(this._decimalPipe.transform(taxAmount, '2.3'));
    this.f.get('paymentAmount').setValue(this._decimalPipe.transform(totalAmount - taxAmount, '2.3'));
  }
  handleSubmit() {
    if (this.formGroup.invalid) {
      this.formGroup.markAllAsTouched();
      return;
    }
    else {
      this._spinner.show();
      let formData = this._commonService.convertFormGroupToFormData(this.formGroup, ['accountID', 'paymentAttachment', 'time', 'dateYMD']);
      formData.append('accountID', this.f.value.accountID && this.f.value.accountID || '');
      if (this.uploadedFile?.['file']) {
        formData.append('paymentAttachment', this.uploadedFile['file']);
      }
      this._receiptsService.addMainFundPaymentReceipt(formData).subscribe({
        next: response => {
          if (response.isSuccess) {
            this.successModal('success', 'Receipt has been created successfully', response.data);
          }
        },
        error: err => {
          this.successModal('error', err?.error.errors || err?.error.Errors);
        }
      }).add(() => {
        this._spinner.hide()
      })
    }
  }
  toggleControlDisability(value: boolean) {
    const controlNames = ['paymentAmount', 'paymentTotalAmount'];
    controlNames.forEach(controlName => {
      const control = this.f.get(controlName);
      if (control) {
        value ? control.enable() : control.disable();
      }
    });
  }
  successModal(type, message, data?) {
    const modelRef = this._modalService.open(ModalMessageComponent, { size: 'md' })
    modelRef.componentInstance.type = type;
    if (type == 'success') {
      modelRef.componentInstance.message = message;
      modelRef.componentInstance.data = { receipt: data };
      modelRef.componentInstance.routeName = "/mainfund-receipt";
    }
    else if (type == 'error') {
      modelRef.componentInstance.messageError = message;
    }
  }
  get f() {
    return this.formGroup;
  }
  get c() {
    return this.formGroup.controls;
  }
  getCurrencyList() {
    this._allocationService.getCurrencyList().subscribe(response => {
      this.currencyList = response['data'].map(x => {
        return { value: x.id, text: x.name[0]?.lookupName }
      });
    })
  }
  fileAction(action) {
    if (action == 'view') {
      const modelRef = this._modalService.open(ViewFileComponent, { size: 'md', })
      modelRef.componentInstance.imageUploadedView = this.uploadedFile;
    }
    else {
      this.inputFile.nativeElement.value = null;
      this.formGroup.get('paymentAttachment')?.setValue('');
      this.uploadedFile = {};
    }
  }
  filesDropped(data: any) {
    this.enter = false;
    let isInvalid = this.checkInvalidImageFormat(data);
    if (isInvalid) {
      this.inputFile.nativeElement.value = null;
      return;
    }
    let files = data.map(x => {
      return x.file
    })
    if (!isInvalid) {
      files.forEach((file: File) => {
        this.formGroup.get('paymentAttachment')?.setValue(file.name);
        this._commonService.fileToBase64(file).then(response => {
          this.uploadedFile = response;
        })
      })
    }
  }

  onSelectFile(event: any) {
    let files = [...event.target.files];
    let isInvalid = this.checkInvalidImageFormat(files);
    if (isInvalid) {
      this.inputFile.nativeElement.value = null;
      return;
    }
    if (files.length > 0) {
      if (!isInvalid) {
        files.forEach((file: File) => {
          this.formGroup.get('paymentAttachment')?.setValue(file.name);
          this._commonService.fileToBase64(file).then(response => {
            this.uploadedFile = response;
          })
        })
      }
    }
  }
  removeFile(item) {
    this.inputFile.nativeElement.value = null;
    this.formGroup.get('paymentAttachment')?.setValue('');
    this.uploadedFile = null;
  }
  checkInvalidImageFormat(data) {
    let files;
    let getFiles = data.map(x => {
      return x.file
    })
    if (getFiles[0] !== undefined) {
      files = getFiles;
    }
    else {
      files = data;
    }
    let invalidExtentions = false;
    for (let file of files) {
      if (!this.fileTypes.includes(file.type)) {
        invalidExtentions = true;
        this.invalidFileType = 'This file not support, supported formates: JPEG, JPG, PNG, PDF';
        this.formGroup.get('paymentAttachment')?.patchValue('');
        setTimeout(() => {
          this.invalidFileType = '';
        }, 3000)
        break;
      }
    }
    return invalidExtentions;
  }
  formatTime(date: Date): string {
    const hours = ('0' + date.getHours()).slice(-2);
    const minutes = ('0' + date.getMinutes()).slice(-2);
    return `${hours}:${minutes}`;
  }
}
