import { Injectable } from '@angular/core';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Observable } from 'rxjs';
import { SharedService } from '../../../../../services/shared.service';

@Injectable({
  providedIn: 'root',
})
export class ReceiptsService {
  apiUrl = this.sharedService.getUrl;
  apiUrl2 = this.sharedService.getUrl2;
  constructor(private http: HttpClient, public sharedService: SharedService) { }
  getMainFundPayments(params: any) {
    return this.http.get(
      this.apiUrl + `Mainfund/GetMainFundPayments${params}`,
      this.sharedService.getHeaders()
    );
  }
  addMainFundPaymentReceipt(payload: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + 'Mainfund/AddMainFundPaymentReceipt',
      payload,
      this.sharedService.getHeaders()
    );
  }
  getMainFundCash(): Observable<any> {
    return this.http.get(
      this.apiUrl + `Mainfund/GetMainFundCash`,
      this.sharedService.getHeaders()
    );
  }
  getEmployees(): Observable<any> {
    return this.http.get<any>(
      this.apiUrl + `User/GetUsers?status=2001&pageNo=0&pageSize=1000`,
      this.sharedService.getHeaders()
    );
  }
  getMainFundPaymentCategories(params:any): Observable<any> {
    return this.http.get<any>(
      //this.apiUrl2 + `MainFundPaymentCategories/GetMainFundPaymentCategories${params}`,
      this.apiUrl2 + `MainFundPaymentCategories/GetMainFundPaymentCategories${params}`,
      this.sharedService.getHeaders()
    );
  }
}
