import { DatePipe } from '@angular/common';
import { Component } from '@angular/core';
import { NgbModal } from '@ng-bootstrap/ng-bootstrap';
import { FormBuilder, FormGroup } from '@angular/forms';
import { TableColumn, TableConfig } from '../../../../shared/components/table-advanced/table-advanced-interfaces';
import { catchError, debounceTime, distinctUntilChanged, forkJoin, of } from 'rxjs';
import { NgxSpinnerService } from 'ngx-spinner';
import { ConfirmModalComponent } from '../../../../shared/components/confirm-modal/confirm-modal.component';
import { ModalMessageComponent } from '../../../../shared/components/modal-message/modal-message.component';
import { ReceiptsService } from './services/receipts.service';
import { MarkaziaVoucherService } from '../../cashier/markazia-vouchers/services/markazia-voucher.service';
import { HeaderService } from '../../../../services/header.service';
import { CommonService } from '../../../../services/common.service';
import { CollectService } from '../../cashier/collect/services/collect.service';
@Component({
  selector: 'app-receipts',
  templateUrl: './receipts.component.html',
  styleUrls: ['./receipts.component.scss']
})
export class ReceiptsComponent {
  mainFundAmounts = [];
  employeeList = [];
  costCenterList = [];
  mfCategoryList = [];
  paymentList = [];
  filterForm: FormGroup;
  filterParams;
  pageNo = 1;
  total = 0;
  limit = 6;
  loading = false;
  tableConfig: TableConfig = {
    paging: true,
    filter: {
      Sort: 1,
      PageSize: this.limit,
    },
  };
  tableColumns: TableColumn[] = [];
  constructor(
    private _receiptsService: ReceiptsService,
    private _voucherService: MarkaziaVoucherService,
    private fb: FormBuilder,
    private _modalService: NgbModal,
    private _headerService: HeaderService,
    public _commonService: CommonService,
    public _collectService: CollectService,
  ) { }
  ngOnInit() {
    this._headerService.setTitle('Main Fund Receipt')
    this.initTableColumns();
    this.initFilterParams();
    this.getPaymentList()
    this.getLookups();
  }
  getLookups() {
    //const employee = this._receiptsService.getEmployees().pipe(catchError(error => of(error)));
    const mainFundAmount = this._receiptsService.getMainFundCash().pipe(catchError(error => of(error)));
    const costCenter = this._voucherService.getCostCenter(`?StatusId=2001&PageSize=1000`).pipe(catchError(error => of(error)));
    const mainFundCat = this._receiptsService.getMainFundPaymentCategories(`?status=2001&PageSize=1000`).pipe(catchError(error => of(error)));
    forkJoin([mainFundAmount, costCenter, mainFundCat]).subscribe(data => {
      //this.employeeList = data[0].data;
      this.mainFundAmounts = data[0].data.filter(x => x.isCash);
      this.costCenterList = data[1].data;
      this.mfCategoryList = data[2].data;
    })
  }
  initFilterParams() {
    this.filterForm = this.fb.group({
      search: [''],
      //paidByUser: [null],
      paidToUser: [null],
      mainFundCategory: [null],
      costCenterId: [null],
    })
    this.filterForm.valueChanges.pipe(debounceTime(500), distinctUntilChanged()).subscribe(value => {
      this.pageNo = 1;
      let formValues = { ...value };
      //if (formValues?.paidByUser == null) {
      //  formValues = { ...formValues, paidByUser: '' }
      //}
      if (formValues?.paidToUser == null) {
        formValues = { ...formValues, paidToUser: '' }
      }
      if (formValues?.mainFundCategory == null) {
        formValues = { ...formValues, mainFundCategory: '' }
      }
      if (formValues?.costCenterId == null) {
        formValues = { ...formValues, costCenterId: '' }
      }
      this.filterParams = '?' + new URLSearchParams(formValues).toString();
      this.getPaymentList()
    })
  }
  getPaymentList() {
    let defaultParams = `pageSize=${this.tableConfig.filter.PageSize}&pageNo=${this.pageNo - 1}&sort=${this.tableConfig.filter.Sort}`;
    let params;
    if (this.filterParams) params = `${this.filterParams}&${defaultParams}`; else params = `?${defaultParams}`;
    this._receiptsService.getMainFundPayments(params).subscribe((response: any) => {
      this.paymentList = response.data;
      this.total = response.totalRecordCount;
    }).add(() => { })
  }
  handleSearch(event: any) {
    this._collectService.customersList(event.term).subscribe((response: any) => {
      this.employeeList = response.data;
    })
  }
  customSearch(term: string, item: any): boolean {
    return item?.customerName?.toLowerCase().includes(term.toLowerCase()) ||
      item?.mobile?.toLowerCase().includes(term.toLowerCase())
  }
  onSortChange(sort: any) {
    if (sort?.direction && sort?.column) {
      switch (sort.column) {
        case 'mainFundPaymentReceiptID':
          this.tableConfig.filter.Sort = sort.direction === 'desc' ? 3 : 2;
          break;
        case 'givenToAccount.fullName':
          this.tableConfig.filter.Sort = sort.direction === 'desc' ? 5 : 4;
          break;
        case 'givenToAccount.userId':
          this.tableConfig.filter.Sort = sort.direction === 'desc' ? 7 : 6;
          break;
        case 'mainFundPaymentTotalAmount':
          this.tableConfig.filter.Sort = sort.direction === 'desc' ? 9 : 8;
          break;
        case 'currency[0].lookupName':
          this.tableConfig.filter.Sort = sort.direction === 'desc' ? 11 : 10;
          break;
        default:
          break;
      }
    } else {
      this.tableConfig.filter.Sort = 1;
    }
    this.getPaymentList();
  }
  onPageChange(page: number) {
    this.pageNo = page;
    this.getPaymentList();
  }
  initTableColumns() {
    this.tableColumns = [
      { key: 'mainFundPaymentReceiptID', label: 'Receipt ID', canSort: true, },
      //{ key: 'createdBy.fullName', label: 'Paid By Employee'},
      { key: 'givenToAccount.fullName', label: 'Account Name', canSort: true, },
      { key: 'givenToAccount.userId', label: 'Account No', canSort: true, },
      { key: 'mainFundPaymentCategory.paymentCategoryName', label: 'Payment Category'},
      { key: 'mainFundPaymentTotalAmount', label: 'Total Amount', canSort: true, currency: { decimalFormat: '2.3-3', appendText: ' JOD' } },
      { key: 'currency[0].lookupName', label: 'Currency', canSort: true, placeholder: '---' },
      { key: 'action', label: 'Action'},
    ];
  }
  responseModal(type, message) {
    const ref = this._modalService.open(ModalMessageComponent);
    ref.componentInstance.type = type;
    ref.componentInstance.dismissOnlyActive = true;
    if (type == 'success')
      ref.componentInstance.message = message;
    else
      ref.componentInstance.messageError = message;
  }
}
